const response = $input.first().json;
const text = response.candidates[0].content.parts[0].text;

const posts = [];
const blocks = text.split(/【投稿[1-3]】/).filter(b => b.trim());

for (let i = 0; i < Math.min(blocks.length, 3); i++) {
  const block = blocks[i];
  const typeMatch = block.match(/タイプ: (.+)/);
  const captionMatch = block.match(/キャプション: ([\s\S]+?)(?=画像プロンプト:|$)/);
  const promptMatch = block.match(/画像プロンプト: (.+)/);

  posts.push({
    postNumber: i + 1,
    type: typeMatch ? typeMatch[1].trim() : 'X',
    caption: captionMatch ? captionMatch[1].trim() : '',
    imagePrompt: promptMatch ? promptMatch[1].trim() : 'modern dating app aesthetic, warm colors, couple silhouette'
  });
}

return posts.map(p => ({json: p}));
